1	export interface Customer {
2	  yearsWithMHPCO: number;
3	}
4	
5	export interface Item {
6	  type: string;
7	  material?: string;
8	  enchantment?: number;
9	  cursed?: boolean;
10	}
11	
12	const PROCESSING_FEE = 5;
13	const FIRST_INSURANCE_SURCHARGE_RATE = 0.1;
14	
15	const BASE_PRICES: Record<string, number> = {
16	  sword: 100,
17	  amulet: 60,
18	  staff: 80,
19	  potion: 40,
20	  rune: 25,
21	  moonstone: 25,
22	};
23	
24	const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
25	const BLOCK_PRICE: Record<string, number> = {
26	  rune: 60,
27	  moonstone: 60,
28	};
29	
30	export function quote(_customer: Customer, items: Item[]): number {
31	  let total = 0;
32	  const componentCounts: Record<string, number> = {};
33	  for (const item of items) {
34	    if (COMPONENT_TYPES.has(item.type)) {
35	      componentCounts[item.type] = (componentCounts[item.type] ?? 0) + 1;
36	      continue;
37	    }
38	    const base = BASE_PRICES[item.type] ?? 0;
39	    const curse = item.cursed ? base * 0.5 : 0;
40	    total += base + curse + base * FIRST_INSURANCE_SURCHARGE_RATE;
41	  }
42	  for (const type of Object.keys(componentCounts)) {
43	    const count = componentCounts[type];
44	    const unitPrice = BASE_PRICES[type] ?? 0;
45	    const base = count === 3 ? BLOCK_PRICE[type] : unitPrice * count;
46	    total += base + base * FIRST_INSURANCE_SURCHARGE_RATE;
47	  }
48	  total += PROCESSING_FEE;
49	  return Math.ceil(total);
50	}
51	
52	export function claim(): unknown {
53	  return undefined;
54	}
